import java.util.Scanner;

public class SecureBufferImplementation {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter a string: ");
        String userInput = scanner.nextLine();

        // Assume the input buffer size is fixed at 10 characters
        char[] buffer = new char[10];

        // Copy user input into the buffer with proper length validation
        if (userInput.length() <= buffer.length) {
            userInput.getChars(0, userInput.length(), buffer, 0);
            System.out.println("Buffer content: " + new String(buffer));
        } else {
            System.out.println("Input exceeds buffer size. Please enter a string of maximum length 10 characters.");
        }
    }
}

